using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class InvoicesTraining : TrainingContentBase
{
    public InvoicesTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Invoices Overview",
            Slug = "invoices-overview",
            Summary = "What the Invoices module does, standalone vs integrated mode, statuses, line items, and how invoices connect to sales orders, shipments, and payments.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/invoices"]""",
            Tags = """["invoices","accounting","billing"]""",
            ContentJson = """{"body":"## Invoices Overview\n\nThe Invoices module handles billing your customers for completed work. Each invoice is a formal request for payment that lists the goods or services provided, their quantities, prices, tax, and the total amount due.\n\n### Accounting Boundary — Standalone vs Integrated Mode\n\nInvoices are an **accounting-bounded feature**. This means the module operates differently depending on whether an accounting provider (e.g., QuickBooks Online) is connected:\n\n- **Standalone mode** (no provider connected): Full CRUD — create, edit, send, void, and delete invoices directly in QB Engineer. This is the default for shops that don't use external accounting software.\n- **Integrated mode** (provider connected): Invoices become **read-only**. They are synced from the accounting system and displayed for reference, but all invoice management happens in the connected provider. A banner at the top of the page indicates which provider is managing invoices.\n\nThe rest of this article describes standalone mode, where you have full control.\n\n### Invoice Statuses\n\nEvery invoice moves through a lifecycle tracked by its status:\n\n- **Draft** (gray chip) — The invoice has been created but not yet sent to the customer. You can still edit, void, or delete it.\n- **Sent** (blue chip) — The invoice has been sent to the customer. It can still be voided, but not deleted.\n- **Partially Paid** (yellow chip) — The customer has made a partial payment. The balance due reflects the remaining amount.\n- **Paid** (green chip) — The invoice is fully paid. The balance due is zero.\n- **Overdue** (red chip) — The due date has passed and the invoice has not been fully paid. The balance due column highlights in red.\n- **Voided** (gray chip) — The invoice has been cancelled. Voided invoices remain in the system for audit purposes but have no financial impact.\n\n### Line Items\n\nEach invoice contains one or more line items. A line item represents a billable entry with:\n- An optional **Part ID** and **Part Number** linking the line to a part in the Parts Catalog\n- A **Description** of the goods or services\n- A **Quantity** and **Unit Price**\n- A computed **Line Total** (Quantity x Unit Price)\n\nThe invoice's **Subtotal** is the sum of all line totals. **Tax** is calculated as Subtotal x Tax Rate. The **Total** is Subtotal + Tax. The **Balance Due** is Total minus any payments applied.\n\n### How Invoices Connect to Other Features\n\n**Sales Orders:** An invoice can be linked to a Sales Order. This connects the billing to the original customer order and lets you trace the full quote-to-cash cycle: Quote → Sales Order → Production → Shipment → Invoice → Payment.\n\n**Shipments:** An invoice can also reference a specific Shipment. This is useful for per-shipment invoicing when a sales order is fulfilled in multiple deliveries.\n\n**Payments:** Payments are applied to invoices through Payment Applications. As payments are recorded, the invoice's Amount Paid increases and Balance Due decreases. When fully paid, the status changes to Paid.\n\n**Jobs:** Completed jobs that haven't been invoiced appear in the Uninvoiced Jobs panel. You can create an invoice directly from a job, which pre-populates the customer and generates line items from the job details.\n\n**Customers:** Every invoice belongs to a customer. The customer link in the invoice detail is clickable and navigates to the customer's full profile.\n\n### PDF Generation\n\nInvoices can be exported as PDF documents for emailing or printing. The server generates the PDF using QuestPDF with your company branding, line items, totals, and payment terms.\n\n### When to Use Invoices\n\n- After completing a job and shipping goods to the customer\n- When billing for services rendered\n- When you need a formal payment request with line items and tax\n- To track payment status and outstanding balances\n- To maintain an audit trail of all billing activity","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Invoices — Guided Tour",
            Slug = "invoices-walkthrough",
            Summary = "A guided tour of the invoices list page: filters, data table, creating invoices, uninvoiced jobs panel, and viewing invoice details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/invoices"]""",
            Tags = """["invoices","accounting","walkthrough"]""",
            ContentJson = """{"appRoute":"/invoices","startButtonLabel":"Tour Invoices","steps":[{"element":"[data-testid='new-invoice-btn']","popover":{"title":"Create Invoice Button","description":"Click here to create a new invoice. A split-layout dialog opens with line items on the left and invoice details (customer, dates, tax rate, credit terms, notes) on the right. You must add at least one line item before saving.","side":"bottom"}},{"element":".page-header .action-btn:first-of-type","popover":{"title":"Uninvoiced Jobs","description":"Opens the Uninvoiced Jobs panel showing completed jobs that haven't been invoiced yet. Each job has a one-click 'Invoice' button to generate an invoice directly. The badge shows how many uninvoiced jobs exist.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Invoices","description":"Search by invoice number, customer name, or other text fields. Press Enter to apply the search filter. Results update in the table below.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Status Filter","description":"Filter invoices by status: Draft, Sent, Partially Paid, Paid, Overdue, or Voided. Select 'All Statuses' to clear the filter and show everything.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Invoices Table","description":"Displays all invoices with columns for Invoice #, Customer, Status (color-coded chip), Invoice Date, Due Date, Total, Paid, and Balance Due. Click any row to open the invoice detail dialog. Click column headers to sort. Overdue balances are highlighted in red.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Invoices Field Reference",
            Slug = "invoices-field-reference",
            Summary = "Complete reference for every field, button, status, validation rule, and action in the Invoices module.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/invoices"]""",
            Tags = """["invoices","accounting","reference"]""",
            ContentJson = """{"title":"Invoices Field Reference","groups":[{"heading":"Invoice Form Fields (Create Dialog — Sidebar)","items":[{"label":"Customer (required)","value":"Dropdown of active customers. Determines who the invoice is billed to. Must select a customer before saving. data-testid: invoice-customer"},{"label":"Sales Order ID","value":"Number input, optional. Links the invoice to an existing Sales Order for traceability through the order-to-cash cycle. Shown as a clickable entity link in the detail view."},{"label":"Invoice Date (required)","value":"Date picker. The date the invoice is issued. Displayed in MM/dd/yyyy format. data-testid: invoice-date"},{"label":"Due Date (required)","value":"Date picker. The date payment is expected. Used to determine Overdue status. Displayed in MM/dd/yyyy format. data-testid: invoice-due-date"},{"label":"Credit Terms","value":"Dropdown of standard credit terms (Net 15, Net 30, Net 45, Net 60, Net 90, Due on Receipt, etc.). Optional. Sets payment expectations for the customer. data-testid: invoice-credit-terms"},{"label":"Tax Rate (required)","value":"Number input with % suffix. The tax percentage applied to the subtotal. Defaults to 0. Must be >= 0. The computed tax amount and grand total update live as you change this value. data-testid: invoice-tax-rate"},{"label":"Shipment ID","value":"Number input, optional. Links the invoice to a specific shipment for per-shipment invoicing."},{"label":"Notes","value":"Textarea, optional. Free-form notes that appear on the invoice. 3 rows visible. data-testid: invoice-notes"}]},{"heading":"Line Item Fields (Create Dialog — Main Area)","items":[{"label":"Part ID","value":"Number input, optional. Links the line item to a part record in the system for traceability."},{"label":"Part Number","value":"Text input, optional. The part number displayed on the invoice. Shown in monospace font in both the dialog table and detail view. data-testid: invoice-line-desc (on description)"},{"label":"Description (required)","value":"Text input. Describes the goods or services being billed. Must not be empty."},{"label":"Qty (required)","value":"Number input. Quantity of items. Must be at least 1. data-testid: invoice-line-qty"},{"label":"Unit Price (required)","value":"Number input. Price per unit. Must be >= 0. Displayed as currency. data-testid: invoice-line-price"},{"label":"Total (computed)","value":"Automatically calculated as Qty x Unit Price. Displayed as currency. Not editable."},{"label":"Add button","value":"Adds the line item to the invoice. Disabled when line form is invalid (missing description or invalid qty/price). data-testid: invoice-add-line-btn"},{"label":"Remove button (X icon)","value":"Red icon button on each line row. Removes the line item from the invoice."}]},{"heading":"Invoice Summary (Create Dialog — Sidebar)","items":[{"label":"Subtotal","value":"Sum of all line item totals. Updates live as lines are added or removed."},{"label":"Tax","value":"Computed as Subtotal x Tax Rate %. Shows the tax rate percentage in parentheses."},{"label":"Total","value":"Subtotal + Tax. Bold, highlighted row. This is the total amount the customer owes."}]},{"heading":"Invoice Statuses","items":[{"label":"Draft (gray chip, chip--muted)","value":"Invoice created but not sent. Can be edited, voided, or deleted. Default status for new invoices."},{"label":"Sent (blue chip, chip--info)","value":"Invoice has been sent to the customer. Can be voided but not deleted. Awaiting payment."},{"label":"Partially Paid (yellow chip, chip--warning)","value":"Customer has made a partial payment. Balance Due shows remaining amount. Cannot be voided or deleted."},{"label":"Paid (green chip, chip--success)","value":"Invoice fully paid. Balance Due is $0.00. No further actions available."},{"label":"Overdue (red chip, chip--error)","value":"Due date has passed with outstanding balance. Balance Due column highlighted in red in the table."},{"label":"Voided (gray chip, chip--muted)","value":"Invoice cancelled. Remains in system for audit trail. No financial impact. Cannot be un-voided."}]},{"heading":"Detail View Fields","items":[{"label":"Invoice Number","value":"Auto-generated identifier displayed in the header with a receipt_long icon."},{"label":"Customer","value":"Clickable entity link that navigates to the customer detail page."},{"label":"Sales Order","value":"Clickable entity link to the linked Sales Order. Only shown if a Sales Order is linked."},{"label":"Shipment","value":"Clickable entity link to the linked Shipment. Only shown if a Shipment is linked."},{"label":"Invoice Date","value":"Date the invoice was issued. Displayed as MM/dd/yyyy."},{"label":"Due Date","value":"Payment due date. Displayed as MM/dd/yyyy."},{"label":"Credit Terms","value":"The payment terms (e.g., Net 30). Only shown if set."},{"label":"Notes","value":"Free-form notes. Only shown if present."},{"label":"Line Items Table","value":"Columns: Part #, Description, Qty, Unit Price, Total. Part numbers in monospace. Dash shown for lines without a part number."},{"label":"Subtotal","value":"Sum of all line totals."},{"label":"Tax (rate%)","value":"Tax amount with the rate shown in parentheses."},{"label":"Total","value":"Grand total (subtotal + tax). Bold styling."},{"label":"Amount Paid","value":"Sum of all payment applications against this invoice."},{"label":"Balance Due","value":"Total minus Amount Paid. Bold styling. Highlighted when non-zero."},{"label":"Created / Updated","value":"Timestamps in MM/dd/yyyy format."},{"label":"Activity Log","value":"Chronological timeline of all changes to the invoice (status changes, edits, etc.)."}]},{"heading":"Buttons and Actions","items":[{"label":"New Invoice (primary button)","value":"Opens the create invoice dialog with split layout. data-testid: new-invoice-btn"},{"label":"Uninvoiced Jobs (header button)","value":"Opens the Uninvoiced Jobs panel showing completed jobs without invoices. Badge shows count."},{"label":"Create Invoice (dialog save)","value":"Saves the new invoice. Disabled when form is invalid, no lines exist, or save is in progress. Shows validation popover on hover when disabled. data-testid: invoice-save-btn"},{"label":"Cancel (dialog)","value":"Closes the create dialog without saving. Prompts if form is dirty (unsaved changes)."},{"label":"Send (detail, primary)","value":"Marks the invoice as Sent. Only available when status is Draft. Icon: send."},{"label":"Void (detail)","value":"Voids the invoice after confirmation dialog. Available when status is Draft or Sent. Icon: block. Confirmation uses warn severity."},{"label":"Delete (detail, danger)","value":"Soft-deletes the invoice after confirmation dialog. Only available when status is Draft. Icon: delete. Confirmation uses danger severity."},{"label":"Close (detail, icon)","value":"Closes the detail dialog. Icon: close. Tooltip: 'Close'."},{"label":"Invoice from Job (uninvoiced panel)","value":"Creates an invoice directly from a completed job. Disabled if the job has no customer assigned. Pre-populates customer and line items."},{"label":"Row click (table)","value":"Opens the invoice detail dialog via DetailDialogService. URL updates to ?detail=invoice:{id} for bookmarkability."}]},{"heading":"Validation Rules","items":[{"label":"Customer","value":"Required. Must select a customer from the dropdown."},{"label":"Invoice Date","value":"Required. Must select a date."},{"label":"Due Date","value":"Required. Must select a date."},{"label":"Tax Rate","value":"Required. Must be a number >= 0."},{"label":"At least one line item","value":"The save button is disabled until at least one line item has been added."},{"label":"Line Description","value":"Required for each line item. Cannot be empty."},{"label":"Line Quantity","value":"Required. Must be >= 1."},{"label":"Line Unit Price","value":"Required. Must be >= 0."},{"label":"Validation popover","value":"Hovering over the disabled Save button shows a bulleted list of which fields need attention."}]},{"heading":"Table Columns (List Page)","items":[{"label":"Invoice # (120px)","value":"Sortable. The auto-generated invoice number. Styled with monospace-like formatting."},{"label":"Customer","value":"Sortable. The customer name."},{"label":"Status (130px)","value":"Sortable, filterable (enum). Color-coded chip: Draft (gray), Sent (blue), Partially Paid (yellow), Paid (green), Overdue (red), Voided (gray)."},{"label":"Invoice Date (110px)","value":"Sortable, date type. The issue date in MM/dd/yyyy format."},{"label":"Due Date (110px)","value":"Sortable, date type. The payment due date in MM/dd/yyyy format."},{"label":"Total (100px, right-aligned)","value":"Sortable. The invoice total displayed as currency."},{"label":"Paid (100px, right-aligned)","value":"Sortable. The amount paid to date displayed as currency."},{"label":"Balance (100px, right-aligned)","value":"Sortable. The remaining balance due. Warning color when balance > 0 and not overdue. Error color when overdue."},{"label":"Created (110px)","value":"Sortable, date type. The creation date in MM/dd/yyyy format."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Invoices Knowledge Check",
            Slug = "invoices-quiz",
            Summary = "Test your knowledge of the Invoices module: statuses, line items, accounting boundary, and common workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/invoices"]""",
            Tags = """["invoices","accounting","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"inv1","text":"Your shop does not use QuickBooks or any other accounting provider. What mode does the Invoices module operate in?","options":[{"id":"a","text":"Integrated mode — invoices are synced from the accounting system"},{"id":"b","text":"Standalone mode — you have full CRUD control over invoices directly in QB Engineer","isCorrect":true},{"id":"c","text":"Read-only mode — invoices can only be viewed, not created"},{"id":"d","text":"Disabled mode — the Invoices page is hidden entirely"}],"explanation":"When no accounting provider is connected, invoices operate in standalone mode with full create, edit, send, void, and delete capabilities. This is the default for shops without external accounting software."},{"id":"inv2","text":"You just finished a job for a customer and need to bill them. What is the fastest way to create an invoice?","options":[{"id":"a","text":"Go to Invoices, click New Invoice, manually enter all the line items"},{"id":"b","text":"Go to Invoices, click the Uninvoiced Jobs button, find the job, and click the Invoice button to auto-generate it","isCorrect":true},{"id":"c","text":"Go to the Kanban board, right-click the job card, and select Create Invoice"},{"id":"d","text":"Go to Sales Orders and convert the order to an invoice"}],"explanation":"The Uninvoiced Jobs panel shows all completed jobs that haven't been invoiced yet. Clicking the Invoice button on a job auto-generates an invoice pre-populated with the customer and job details."},{"id":"inv3","text":"An invoice has a status of 'Sent' (blue chip). Which actions are available?","options":[{"id":"a","text":"Edit, Void, Delete, and Send"},{"id":"b","text":"Void only — you can cancel the invoice but cannot delete or edit it","isCorrect":true},{"id":"c","text":"Delete only — you can remove the invoice from the system"},{"id":"d","text":"No actions — Sent invoices are locked and cannot be changed"}],"explanation":"Sent invoices can be voided (cancelled) but cannot be deleted. The Delete action is only available for Draft invoices. This preserves the audit trail for invoices that have already been sent to customers."},{"id":"inv4","text":"What does the yellow 'Partially Paid' status chip indicate?","options":[{"id":"a","text":"The customer has paid exactly half of the invoice total"},{"id":"b","text":"The customer has made at least one payment, but the Balance Due is still greater than zero","isCorrect":true},{"id":"c","text":"The invoice is pending approval before it can be sent"},{"id":"d","text":"The invoice tax calculation is incomplete"}],"explanation":"Partially Paid means one or more payments have been applied to the invoice, but the total amount paid is less than the invoice total. The Balance Due field shows exactly how much remains."},{"id":"inv5","text":"You need to create an invoice with 3 line items. When is the Save button enabled?","options":[{"id":"a","text":"As soon as you fill in the customer and dates"},{"id":"b","text":"After selecting a customer, filling in dates, setting tax rate, AND adding at least one line item","isCorrect":true},{"id":"c","text":"After adding all 3 line items — the form knows you intended 3"},{"id":"d","text":"The Save button is always enabled and validates on click"}],"explanation":"The Save button requires: a customer selected, invoice date set, due date set, tax rate >= 0, and at least one line item added. The button is disabled and shows a validation popover on hover until all requirements are met."},{"id":"inv6","text":"How is the invoice Total calculated?","options":[{"id":"a","text":"Sum of all line item unit prices"},{"id":"b","text":"Subtotal (sum of line totals) plus Tax Amount (Subtotal x Tax Rate)","isCorrect":true},{"id":"c","text":"Sum of all line quantities multiplied by a flat rate"},{"id":"d","text":"Manually entered by the user in the Total field"}],"explanation":"The Total is computed automatically: Subtotal (sum of Qty x Unit Price for each line) + Tax Amount (Subtotal x Tax Rate %). All three values update live as you add/remove lines or change the tax rate."},{"id":"inv7","text":"You see a red Balance Due amount in the invoices table. What does this mean?","options":[{"id":"a","text":"The invoice has a negative balance (overpayment)"},{"id":"b","text":"The invoice is Overdue — the due date has passed and it hasn't been fully paid","isCorrect":true},{"id":"c","text":"The invoice was voided and the balance is being refunded"},{"id":"d","text":"The tax rate exceeds the maximum allowed percentage"}],"explanation":"The Balance Due column uses red (error) styling when the invoice status is Overdue, meaning the due date has passed with an outstanding balance. Non-overdue invoices with a balance show a warning (yellow) color instead."},{"id":"inv8","text":"A customer sends you a mold for production. The completed job appears in Uninvoiced Jobs but the Invoice button is disabled. Why?","options":[{"id":"a","text":"The job hasn't been marked as complete yet"},{"id":"b","text":"The job has no customer assigned — you must assign a customer to the job before invoicing","isCorrect":true},{"id":"c","text":"The invoice module is in integrated mode"},{"id":"d","text":"There are too many uninvoiced jobs in the queue"}],"explanation":"The Invoice button in the Uninvoiced Jobs panel is disabled when a job has no customer assigned. The tooltip reads 'No customer assigned'. You need to assign a customer to the job first, then the button becomes active."},{"id":"inv9","text":"What happens when you Void an invoice?","options":[{"id":"a","text":"The invoice is permanently deleted from the database"},{"id":"b","text":"The invoice status changes to Voided (gray chip) and it remains in the system for audit purposes with no financial impact","isCorrect":true},{"id":"c","text":"The invoice is moved to a separate Voided Invoices archive page"},{"id":"d","text":"All payments applied to the invoice are automatically refunded"}],"explanation":"Voiding an invoice sets its status to Voided and preserves the record for audit purposes. QB Engineer uses soft deletes — nothing is permanently removed. A confirmation dialog with warn severity appears before voiding."},{"id":"inv10","text":"You connected QuickBooks Online to QB Engineer. What happens to the Invoices page?","options":[{"id":"a","text":"Nothing changes — invoices work exactly the same"},{"id":"b","text":"The page shows a banner indicating invoices are managed by QuickBooks, and invoice creation/editing is disabled (read-only)","isCorrect":true},{"id":"c","text":"The Invoices page is completely hidden from navigation"},{"id":"d","text":"Only the New Invoice button is hidden — you can still edit existing invoices"}],"explanation":"When an accounting provider is connected, the Invoices module switches to integrated mode. A cloud_sync banner appears at the top, and all CRUD operations are disabled. Invoices are synced from QuickBooks and displayed read-only."},{"id":"inv11","text":"In the invoice detail view, you see clickable blue links for 'Customer', 'Sales Order', and 'Shipment'. What do these links do?","options":[{"id":"a","text":"They copy the entity ID to your clipboard"},{"id":"b","text":"They open the respective entity's detail dialog or page, allowing you to navigate the full order-to-cash chain","isCorrect":true},{"id":"c","text":"They send an email notification to the related entity's owner"},{"id":"d","text":"They export a PDF report for the linked entity"}],"explanation":"These are EntityLink components that provide clickable cross-references. Customer links navigate to the customer detail page. Sales Order and Shipment links open their respective detail dialogs via the ?detail=type:id URL pattern."},{"id":"inv12","text":"You want to find all overdue invoices for a specific customer. What is the most efficient approach?","options":[{"id":"a","text":"Export all invoices to CSV and filter in a spreadsheet"},{"id":"b","text":"Set the Status filter to Overdue, then use the Search box to type the customer name","isCorrect":true},{"id":"c","text":"Go to the customer's profile page and check the Invoices tab"},{"id":"d","text":"Run a report from the Reports module filtered by invoice status"}],"explanation":"The Invoices page has both a Status filter dropdown and a Search box. Set Status to Overdue to see only overdue invoices, then type the customer name in the Search box to narrow the results. Both filters work together."}]}"""
        });

        Log.Information("Seeded Invoices training modules");
    }
}
